sysauto_script.script:
// AIROP Scheduled Assessment
// Checks for a running assessment record and executes checks
try {
    gs.info('[AIROP] Scheduled job fired: ' + new GlideDateTime());

    // Check if there is already a running record (triggered by UI)
    var runningGr = new GlideRecord('x_snc_airop_assessment_run');
    runningGr.addQuery('status', 'running');
    runningGr.orderByDesc('run_date');
    runningGr.setLimit(1);
    runningGr.query();

    if (!runningGr.next()) {
        gs.info('[AIROP] No running record found - nothing to do.');
        return;
    }

    var runId = runningGr.getUniqueValue();
    gs.info('[AIROP] Picked up running record: ' + runId + ' | ' + runningGr.getValue('name'));

    // Populate modules_scanned if not already set
    if (!runningGr.getValue('modules_scanned')) {
        var pMap = {
            'ITSM':            'x_snc_airop.run_itsm',
            'ITOM':            'x_snc_airop.run_itom',
            'CMDB':            'x_snc_airop.run_cmdb',
            'HRSD':            'x_snc_airop.run_hrsd',
                        'CSM':             'x_snc_airop.run_csm',
            'FIELD_SERVICE':   'x_snc_airop.run_field_service',
            'AIOPS':           'x_snc_airop.module.AIOPS.enabled',
            'GRC':             'x_snc_airop.run_grc',
            'SPM':             'x_snc_airop.run_spm',
                        'PLATFORM':        'x_snc_airop.run_platform',
                        'VIRTUAL_AGENT':   'x_snc_airop.run_virtual_agent',
            'DEX':             'x_snc_airop.module.DEX.enabled',
            'SECOPS':          'x_snc_airop.module.SECOPS.enabled',
            'HS':          'x_snc_airop.module.HS.enabled',
            'OTSM':          'x_snc_airop.module.OTSM.enabled',
            'CREATOR':          'x_snc_airop.module.CREATOR.enabled',
            'SPO':          'x_snc_airop.module.SPO.enabled',
            'TPRM':          'x_snc_airop.module.TPRM.enabled',
            'LSD':          'x_snc_airop.module.LSD.enabled',
            'WSD':          'x_snc_airop.module.WSD.enabled',
            'HAM':          'x_snc_airop.module.HAM.enabled',
            'SAM':          'x_snc_airop.module.SAM.enabled'
        };
        var enabled = [];
        for (var mod in pMap) {
            if (gs.getProperty(pMap[mod], 'false') === 'true') enabled.push(mod);
        }
        runningGr.setValue('modules_scanned', enabled.join(', '));
        runningGr.update();
        gs.info('[AIROP] modules_scanned set to: ' + enabled.join(', '));
    }

    // Execute the runner
    var runner = new AROPRunner();
    runner.executeWithRunId(runId);

} catch(e) {
    gs.error('[AIROP] Scheduled job error: ' + e.message);
    gs.error('[AIROP] Stack: ' + e.stack);
}
